while running:
    screen.fill("black")
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            running = False
        if event.type == pygame.MOUSEMOTION:
            moving = True
            mx = pygame.mouse.get_pos()
            anglex = -mx[0]/100
            angley = -mx[1]/100
        #movement
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_w:
                for i in range(len(shape)):
                    print("forward")
                    x,y,z = shape[i]
                    z -= 0.1
                    shape[i] = (x,y,z)
            if event.key == pygame.K_s:
                print("backward")
                for i in range(len(shape)):
                    x,y,z = shape[i]
                    z += 0.1
                    shape[i] = (x,y,z)
            if event.key == pygame.K_SPACE:
                if moving:
                    moving = False
                else:
                    moving = True
    if moving==False:
        anglex += velocityx
        angley += velocityy
        velocityx += random.randint(-100, 100)/100000
        velocityy += random.randint(-100, 100)/100000
    projected_points = []
    tr_z = []
    for x, y, z in shape:
        # XAxis Rotation
        ry = y * math.cos(angley) - z * math.sin(angley)
        rz = y * math.sin(angley) + z * math.cos(angley)
        #Y axis rotation
        rx = x * math.cos(anglex) + rz * math.sin(anglex)
        rz = x * -math.sin(anglex) + rz * math.cos(anglex)

        z_depth = rz+4
        
        px = (rx * f_length) / z_depth + 640 
        py = (ry * f_length) / z_depth + 360
        projected_points.append((px, py))
        tr_z.append(z_depth)
    #for i in range(len(projected_points)):
    #    pygame.draw.circle(screen, "white", projected_points[i], 5)
    face_list = []
    for face in faces:
        # Average Z-depth of all vertices in this specific face
        avg_z = sum(tr_z[i] for i in face) / len(face)
        face_list.append((avg_z, face))
    face_list.sort(key=lambda x: x[0], reverse=True)
    mincolor = min(tr_z)
    maxcolor = max(tr_z)
    #for edge in edges:
    #    pygame.draw.line(screen, "white", projected_points[edge[0]], projected_points[edge[1]], 10)
    for depth, face in face_list:
        
        color_val = (depth-mincolor)/(maxcolor-mincolor)
        color_val *= 255
        points = [projected_points[i] for i in face]
        pygame.draw.polygon(screen, (color_val, color_val, color_val), points)
    
    pygame.display.flip()
    clock.tick(60)
pygame.quit()
